class Solution {
public:
    int numMusicPlaylists(int n, int goal, int k) {
        const int MOD = 1e9 + 7;
        vector<vector<int>> dp(goal + 1, vector<int>(goal + 1, 0));
        dp[0][0] = 1;

        for (int i = 1; i <= goal; ++i) {
            for (int j = 0; j <= min(i, n); ++j) {
                if (j > 0) dp[i][j] = (dp[i][j] + dp[i - 1][j - 1] * (n - j + 1)) % MOD;
                if (j > k) dp[i][j] = (dp[i][j] + dp[i - 1][j] * (j - k)) % MOD;
            }
        }

        return dp[goal][n];
    }
};
